20	// Runes and moonstones are "components" — a distinct pricing tier that shares
21	// one base premium (and, later, block/alike rules). Naming the shared value
22	// makes the equality intentional rather than a coincidence two entries happen
23	// to share.
24	const COMPONENT_BASE_PREMIUM = 25;
25	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
26	// A "building block" of exactly this many alike components is offered at a
27	// special block premium instead of the per-component price.
28	const COMPONENT_BLOCK_SIZE = 3;
29	const COMPONENT_BLOCK_PREMIUM = 60;
30	
31	const BASE_PREMIUMS: Record<string, number> = {
32	  sword: 100,
33	  amulet: 60,
34	  staff: 80,
35	  potion: 40,
36	  rune: COMPONENT_BASE_PREMIUM,
37	  moonstone: COMPONENT_BASE_PREMIUM,
38	};
39	const PROCESSING_FEE = 5;
40	
41	// First-insurance surcharge of +10%, expressed as a numerator/denominator pair
42	// so the maths stays in integers: `base * 110 / 100` avoids the float error of
43	// `base * 1.1` (e.g. 100 * 1.1 === 100.00000000000001).
44	const FIRST_INSURANCE_SURCHARGE_NUMERATOR = 110;
45	const FIRST_INSURANCE_SURCHARGE_DENOMINATOR = 100;
46	
47	const countByType = (items: Item[]): Map<string, number> => {
48	  const counts = new Map<string, number>();
49	  for (const item of items) {
50	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
51	  }
52	  return counts;
53	};
54	
55	const componentGroupPremium = (count: number): number => {
56	  const blocks = Math.floor(count / COMPONENT_BLOCK_SIZE);
57	  const remainder = count % COMPONENT_BLOCK_SIZE;
58	  return blocks * COMPONENT_BLOCK_PREMIUM + remainder * COMPONENT_BASE_PREMIUM;
59	};
60	
61	const sumBasePremiums = (items: Item[]): number => {
62	  let total = 0;
63	  for (const [type, count] of countByType(items)) {
64	    total += COMPONENT_TYPES.has(type)
65	      ? componentGroupPremium(count)
66	      : count * (BASE_PREMIUMS[type] ?? 0);
67	  }
68	  return total;
69	};
70	
71	export const quote = (
72	  _customer: Customer,
73	  step: QuoteStep,
74	  _quoteIndex: number,
75	): QuoteResult => {
76	  const basePremium = sumBasePremiums(step.items);
77	  const withFirstInsurance =
78	    (basePremium * FIRST_INSURANCE_SURCHARGE_NUMERATOR) /
79	    FIRST_INSURANCE_SURCHARGE_DENOMINATOR;
80	  const premium = Math.ceil(withFirstInsurance + PROCESSING_FEE);
81	  return { premium };
82	};
83	
84	export const claim = (): unknown => {
85	  return undefined;
86	};
